-- ============================================================================
-- Clinical Co-Pilot test seed  (evergreen: dates are relative to load time)
-- Populates a type-2-diabetes endocrinology day: cohort + scheduled clinic +
-- A1c series, meds, vitals trend, overdue tests, and pending results so the
-- LLM synthesis and the pinned chat agent have real, cited facts to work over.
--
-- Load AFTER a normal OpenEMR install:  mysql -u <u> -p <db> < copilot_test_seed.sql
-- Re-runnable: it clears its own id ranges first.
-- ============================================================================

SET @prov := 90;

-- Clear any previous run of this seed (id ranges are reserved for it).
DELETE FROM `patient_data` WHERE `pid` BETWEEN 9001 AND 9101;
DELETE FROM `form_encounter` WHERE `pid` BETWEEN 9001 AND 9101;
DELETE FROM `forms` WHERE `pid` BETWEEN 9001 AND 9101;
DELETE FROM `form_vitals` WHERE `pid` BETWEEN 9001 AND 9101;
DELETE FROM `lists` WHERE `pid` BETWEEN 9001 AND 9101;
DELETE FROM `prescriptions` WHERE `patient_id` BETWEEN 9001 AND 9101;
DELETE FROM `procedure_result` WHERE `procedure_report_id` BETWEEN 710000 AND 719999;
DELETE FROM `procedure_report` WHERE `procedure_order_id` BETWEEN 700000 AND 709999;
DELETE FROM `procedure_order_code` WHERE `procedure_order_id` BETWEEN 700000 AND 709999;
DELETE FROM `procedure_order` WHERE `patient_id` BETWEEN 9001 AND 9101;
DELETE FROM `openemr_postcalendar_events` WHERE `pc_pid` BETWEEN 9001 AND 9101;
DELETE FROM `users` WHERE `id` = 90;

